import React from 'react';
import ReactDOM from 'react-dom/client';
import { BrowserRouter } from 'react-router-dom';

// Importa o componente principal da aplicação
import App from './App'; 

// Importa TODOS os seus estilos globais, variáveis, fontes, etc.
import './styles/globals.css';

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    {/* O BrowserRouter é necessário aqui para que o roteamento funcione em toda a aplicação */}
    <BrowserRouter>
      <App />
    </BrowserRouter>
  </React.StrictMode>
);
